// Validate input
const body = $input.first().json.body || $input.first().json;

if (!body.xml_ref) {
  throw new Error('Missing required field: xml_ref');
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  event: 'employers_plus_received'
}));

return { xml_ref: body.xml_ref };

// Extract employee codes from XML CDATA
const xmlString = $input.first().json.xml_ref;

// Extract CDATA content
const cdataMatch = xmlString.match(/<!\[CDATA\[(.*?)\]\]>/s);
if (!cdataMatch) {
  throw new Error('No CDATA section found in the provided XML.');
}

const htmlContent = cdataMatch[1].trim();

// Parse HTML to extract tr elements with codigo attribute
const trRegex = /<tr[^>]*class="table-row-body"[^>]*codigo="([^"]+)"/g;
const codes = [];
let match;

while ((match = trRegex.exec(htmlContent)) !== null) {
  codes.push({ codigo: match[1] });
}

if (codes.length === 0) {
  throw new Error('No table rows with class "table-row-body" and codigo attribute found.');
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  event: 'employers_plus_extracted',
  codes_count: codes.length
}));

return { ids: codes };

// Build response
const data = $input.first().json;

return {
  statusCode: 200,
  body: {
    message: 'Employee codes extracted successfully.',
    ids: data.ids
  }
};
